import os
import hashlib
from functools import wraps
from flask import Flask, session, redirect, url_for, request, jsonify

app = Flask(__name__)
app.secret_key = os.urandom(24)

users_db = {}
sessions_db = {}

def generate_session_id(username):
    random_data = os.urandom(16)
    return hashlib.sha256((username + str(random_data)).encode()).hexdigest()

def create_user(username, password):
    if username in users_db:
        return False
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    users_db[username] = password_hash
    return True

def verify_user(username, password):
    if username not in users_db:
        return False
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    return users_db[username] == password_hash

def login_user(username):
    session_id = generate_session_id(username)
    sessions_db[session_id] = username
    session['session_id'] = session_id
    session['username'] = username
    return session_id

def logout_user():
    session_id = session.get('session_id')
    if session_id and session_id in sessions_db:
        del sessions_db[session_id]
    session.clear()

def is_logged_in():
    session_id = session.get('session_id')
    username = session.get('username')
    if not session_id or not username:
        return False
    return session_id in sessions_db and sessions_db[session_id] == username

def get_current_user():
    if is_logged_in():
        return session.get('username')
    return None

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not is_logged_in():
            return redirect(url_for('login_page'))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/register', methods=['POST'])
def register():
    username = request.form.get('username')
    password = request.form.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if create_user(username, password):
        return jsonify({'message': 'User created successfully'}), 201
    else:
        return jsonify({'error': 'User already exists'}), 409

@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username')
    password = request.form.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if verify_user(username, password):
        login_user(username)
        return jsonify({'message': 'Logged in successfully', 'username': username}), 200
    else:
        return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/logout', methods=['POST'])
def logout():
    logout_user()
    return jsonify({'message': 'Logged out successfully'}), 200

@app.route('/login')
def login_page():
    return jsonify({'message': 'Please login'}), 401

@app.route('/profile')
@login_required
def profile():
    username = get_current_user()
    return jsonify({'username': username, 'message': 'This is a protected route'}), 200

@app.route('/status')
def status():
    if is_logged_in():
        return jsonify({'logged_in': True, 'username': get_current_user()}), 200
    else:
        return jsonify({'logged_in': False}), 200

if __name__ == '__main__':
    app.run(debug=True)